				//dispatch.Assigns[dispatch.AssignsLen].AddShip(total_ship + jj, oris[jj], dess[jj])
				//checkDispatch(&dispatch)
				break
			}
		}
	}
	dispatch.RenewnTotalCost()
	//XXX: 调查发现,insertion不会改变累计里程，是别的东西删除了累计里程
	return dispatch
